selector_to_html = {"a[href=\"#equation-a8e62232-2b00-4ac1-9cd4-001f1efa2ec9\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-a8e62232-2b00-4ac1-9cd4-001f1efa2ec9\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-101bf92f-d0fa-49b7-a520-2cbcf6ef3698\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-101bf92f-d0fa-49b7-a520-2cbcf6ef3698\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Decaimiento de la oscilaci\u00f3n de un p\u00e9ndulo debido a un chorro de aire<a class=\"headerlink\" href=\"#decaimiento-de-la-oscilacion-de-un-pendulo-debido-a-un-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>Cabe recordar que la ecuaci\u00f3n presentada por <span id=\"id3\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> est\u00e1 dada como sigue</p>", "a[href=\"#equation-56ecf1c0-415f-4a36-8216-38d3ae80ed4f\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-56ecf1c0-415f-4a36-8216-38d3ae80ed4f\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-1a7a6ca2-2815-4fb1-8341-ad86f74f58e7\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-1a7a6ca2-2815-4fb1-8341-ad86f74f58e7\">\n\\[\\begin{equation}\n \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ f(t) = \\frac{1}{\\sigma^{1-\\alpha}}~ t^{1-\\alpha}~ \\frac{\\mathrm{d}f}{\\mathrm{d}t}.\n\\end{equation}\\]</div>", "a[href=\"#equation-442f18f2-be22-4b6c-addd-23785c08af2d\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-442f18f2-be22-4b6c-addd-23785c08af2d\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#generacion-de-datos-experimentales-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Generaci\u00f3n de datos experimentales sint\u00e9ticos<a class=\"headerlink\" href=\"#generacion-de-datos-experimentales-sinteticos\" title=\"Link to this heading\">#</a></h2><p>Ante la ausencia de datos experimentales f\u00edsicos para esta configuraci\u00f3n espec\u00edfica del p\u00e9ndulo, se generaron datos sint\u00e9ticos para probar rigurosamente el algoritmo de estimaci\u00f3n de par\u00e1metros. El conjunto de datos sint\u00e9ticos se produjo simulando el modelo cl\u00e1sico exacto (<span class=\"math notranslate nohighlight\">\\(\\alpha=1\\)</span>) e inyectando un <span class=\"math notranslate nohighlight\">\\(2\\%\\)</span> de ruido gaussiano para simular las imprecisiones de los sensores en el mundo real.</p><p>Esto proporciona un entorno de validaci\u00f3n controlado: el sistema verdadero subyacente opera precisamente en <span class=\"math notranslate nohighlight\">\\(\\alpha=1\\)</span>, lo que permite evaluar si la optimizaci\u00f3n converge correctamente al sistema cl\u00e1sico.</p>", "a[href=\"#equation-944c77f8-6549-4526-9ab2-f33db2113b4e\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-944c77f8-6549-4526-9ab2-f33db2113b4e\">\n\\[\\begin{equation}\n {}^{K}\\mathcal{D}_{t}^{\\alpha}~ f(t) = t^{1-\\alpha} \\frac{df}{dt}.\n\\end{equation}\\]</div>", "a[href=\"#equation-951b0abb-ff38-47e8-b562-68dad4dcd87e\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-951b0abb-ff38-47e8-b562-68dad4dcd87e\">\n\\[\\begin{equation}\n \\begin{aligned}\n  t^{1-\\alpha} \\dot{x}_1 &amp;= x_2 \\quad \\Rightarrow \\quad \\dot{x}_1 = t^{\\alpha-1} x_2, \\\\\n  t^{1-\\alpha} \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\quad \\Rightarrow \\quad \\dot{x}_2 = t^{\\alpha-1} \\left( -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2 \\right).\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-1364e192-8d82-4b33-8b9d-479d57420ac5\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-1364e192-8d82-4b33-8b9d-479d57420ac5\">\n\\[\\begin{equation}\n \\frac{1}{\\sigma^{0}} D^1 f(t) = 1 \\cdot t^0 \\frac{df}{dt} = \\frac{df}{dt},\n\\end{equation}\\]</div>", "a[href=\"#equation-81989adf-f4eb-4964-a3f9-83d927f13fcb\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-81989adf-f4eb-4964-a3f9-83d927f13fcb\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  \\frac{1}{\\sigma^{1-\\alpha}}~ {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-con-efectos-de-chorro-de-aire\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo con efectos de chorro de aire<a class=\"headerlink\" href=\"#pendulo-con-efectos-de-chorro-de-aire\" title=\"Link to this heading\">#</a></h2><p>La ecuaci\u00f3n cl\u00e1sica del p\u00e9ndulo con efectos de chorro de aire fue propuesta por <span id=\"id1\">Hasan <em>et al.</em> (<a class=\"reference internal\" href=\"../references.html#id3\" title=\"Hasan, M. S., Deepu, P., Kumar, K., Agrawal, A., &amp; Meena, D. K. (2023). Oscillation decay of a pendulum by an air jet. Physics Letters A, 481, 129003.\">2023</a>)</span> y est\u00e1 dada como sigue</p>", "a[href=\"#interpretacion-fisica\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Interpretaci\u00f3n f\u00edsica<a class=\"headerlink\" href=\"#interpretacion-fisica\" title=\"Link to this heading\">#</a></h2><p>El factor de escalamiento dependiente del tiempo <span class=\"math notranslate nohighlight\">\\(t^{\\alpha-1}\\)</span> tiene implicaciones f\u00edsicas interesantes:</p>", "a[href=\"#perfil-de-verosimilitud-para-sigma\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Perfil de verosimilitud para <span class=\"math notranslate nohighlight\">\\(\\sigma\\)</span><a class=\"headerlink\" href=\"#perfil-de-verosimilitud-para-sigma\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#equation-75a112f5-32b9-4b64-a793-04c934c85586\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-75a112f5-32b9-4b64-a793-04c934c85586\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1}~ \\sigma^{1-\\alpha}~ x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1}~ \\sigma^{1-\\alpha}~ \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right].\n\\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#optimizacion-multietapa\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Optimizaci\u00f3n Multietapa<a class=\"headerlink\" href=\"#optimizacion-multietapa\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Graficaci\u00f3n del ajuste optimizado vs. datos sint\u00e9ticos<a class=\"headerlink\" href=\"#graficacion-del-ajuste-optimizado-vs-datos-sinteticos\" title=\"Link to this heading\">#</a></h2><p>Se grafica la soluci\u00f3n verdadera sin ruido, los datos sint\u00e9ticos ruidosos y el modelo optimizado. Los residuales demuestran que el ajuste es satisfactorio: el nivel de ruido se captura correctamente y el optimizador ha recuperado par\u00e1metros cercanos a los valores verdaderos.</p>", "a[href=\"#equation-8fedf089-6e9a-46a6-a6b0-785caedaaf1f\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-8fedf089-6e9a-46a6-a6b0-785caedaaf1f\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1}~ x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1}~ \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right],\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-1a42049a-2d6f-40ee-9930-73fa88ffb4a2\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-1a42049a-2d6f-40ee-9930-73fa88ffb4a2\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= t^{\\alpha-1} x_2, \\\\\n  \\dot{x}_2 &amp;= t^{\\alpha-1} \\left[ -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2) \\right].\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-d72747f2-ddee-4493-98c1-6d57d64d3b08\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-d72747f2-ddee-4493-98c1-6d57d64d3b08\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\alpha\\omega_n^2 \\sin(x_1) - c|x_2|x_2 - \\alpha\\eta|\\cos(x_1)|\\operatorname{sgn}(x_2),\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#equation-39ad9203-b587-4ab7-9460-38f6797a7201\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-39ad9203-b587-4ab7-9460-38f6797a7201\">\n\\[\\begin{equation}\n \\begin{aligned}\n  \\dot{x}_1 &amp;= x_2, \\\\\n  \\dot{x}_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2,\n \\end{aligned}\n\\end{equation}\\]</div>", "a[href=\"#pendulo-simple\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">P\u00e9ndulo simple<a class=\"headerlink\" href=\"#pendulo-simple\" title=\"Link to this heading\">#</a></h1><p>Para establecer una l\u00ednea de base, primero se define el sistema cl\u00e1sico del p\u00e9ndulo no lineal con amortiguamiento. Las ecuaciones gobernantes son:</p><p><strong>Sistema cl\u00e1sico original del p\u00e9ndulo</strong></p>", "a[href=\"#equation-54266ace-20cc-47f1-b5b3-f0c9859bf892\"]": "<div class=\"amsmath math notranslate nohighlight\" id=\"equation-54266ace-20cc-47f1-b5b3-f0c9859bf892\">\n\\[\\begin{equation}\n \\begin{aligned}\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_1 &amp;= x_2, \\\\\n  {}^{K}\\mathcal{D}_{t}^{\\alpha}~ x_2 &amp;= -\\frac{g}{l} \\sin(x_1) - \\frac{K_f}{m} x_2.\n \\end{aligned}\n\\end{equation}\\]</div>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(`article.bd-article ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: false,
                placement: 'auto-start', maxWidth: 500, interactive: true, boundary: document.body, appendTo: document.body,
                onShow(instance) {MathJax.typesetPromise([instance.popper]).then(() => {var isFirefox=typeof InstallTrigger!=='undefined';if(isFirefox&&window.MathJax&&MathJax.startup&&MathJax.startup.output&&MathJax.startup.output.name==="SVG"){const svgs=instance.popper.querySelectorAll('svg');svgs.forEach(svg=>{let bbox=svg.getBBox(),x=bbox.x,y=bbox.y,width=bbox.width,height=bbox.height;svg.setAttribute('width',width);svg.setAttribute('height',height);svg.setAttribute('viewBox',`${x} ${y} ${width} ${height}`);});let rescale=0.015;svgs.forEach(svg=>{let bbox=svg.getBBox(),width=bbox.width,height=bbox.height;svg.setAttribute('width',width*rescale);svg.setAttribute('height',height*rescale);});}});},
            });
        };
    };
    console.log("tippy tips loaded!");
};
